mapper.update:
UPDATE t_repair_building_process
SET status = #{nextStatus}, process_version = process_version + 1,
    update_time = CURRENT_TIMESTAMP
WHERE process_id = #{processId}
  AND tenant_id = #{tenantId}
  AND status = #{expectedStatus}
  AND process_version = #{expectedVersion}

UPDATE t_repair_building_process
SET official_document_attachment_id = #{attachmentId},
    status = 'OFFICIAL_DOCUMENT_READY',
    process_version = process_version + 1,
    update_time = CURRENT_TIMESTAMP
WHERE process_id = #{processId}
  AND tenant_id = #{tenantId}
  AND status = 'DECISION_PASSED'
  AND process_version = #{expectedVersion}

UPDATE t_repair_building_process
SET approved_by_user_id = #{approvedByUserId}, approver_position = #{approverPosition},
    approval_opinion = #{opinion}, approved_at = CURRENT_TIMESTAMP,
    status = 'COMMITTEE_APPROVED', process_version = process_version + 1,
    update_time = CURRENT_TIMESTAMP
WHERE process_id = #{processId}
  AND tenant_id = #{tenantId}
  AND status = 'PRICE_REVIEWED'
  AND price_review_conclusion = 'APPROVED'
  AND process_version = #{expectedVersion}

UPDATE t_repair_building_process
SET seal_usage_id = #{sealUsageId}, status = 'AUTHORIZED',
    process_version = process_version + 1, update_time = CURRENT_TIMESTAMP
WHERE process_id = #{processId}
  AND tenant_id = #{tenantId}
  AND status = 'COMMITTEE_APPROVED'
  AND process_version = #{expectedVersion}

